interface MetadataSectionProps {
  image: Image
  isPurchased: boolean
}

function formatFileSize(bytes: number): string {
  if (bytes >= 1024 * 1024) return (bytes / (1024 * 1024)).toFixed(1) + ' MB'
  return Math.round(bytes / 1024) + ' KB'
}

export function MetadataSection({ image, isPurchased }: MetadataSectionProps) {
  if (!isPurchased) {
    return (
      <div className="relative rounded-lg border border-gray-200 p-5 overflow-hidden">
        <div className="blur-sm select-none pointer-events-none space-y-3">
          {/* 더미 플레이스홀더 행 4개 */}
          {/* 실제 데이터 절대 노출 금지 */}
        </div>
        <div className="absolute inset-0 flex flex-col items-center justify-center bg-white/80">
          <Lock className="h-8 w-8 text-gray-400 mb-2" />
          <p className="text-sm font-medium text-gray-700">구매 후 확인 가능</p>
          <p className="text-xs text-gray-500 mt-1">이 이미지를 구매하면 상세 정보를 확인할 수 있습니다</p>
        </div>
      </div>
    )
  }

  const SIZES: ImageSize[] = ['XL', 'L', 'M', 'S']
  return (
    <div className="space-y-4">
      <h3 className="text-sm font-semibold text-gray-900">이미지 정보</h3>
      <dl className="space-y-2">
        <MetaRow label="이미지 코드" value={image.code} />
        <MetaRow label="해상도" value={image.width + '×' + image.height} />
        <MetaRow label="포맷" value={image.format.toUpperCase()} />
        {image.shootDate && <MetaRow label="촬영 연월" value={image.shootDate} />}
      </dl>
      <div>
        <p className="text-xs font-medium text-gray-500 mb-2">파일 크기</p>
        <div className="grid grid-cols-4 gap-2">
          {SIZES.map(s => (
            <div key={s} className="rounded-md bg-gray-50 p-2 text-center">
              <div className="text-xs font-semibold text-gray-700">{s}</div>
              <div className="text-xs text-gray-500 mt-0.5">{formatFileSize(image.fileSizesJson[s])}</div>
            </div>
          ))}
        </div>
      </div>
      {image.colorTags.length > 0 && (
        <div>
          <p className="text-xs font-medium text-gray-500 mb-2">색상 태그</p>
          <div className="flex flex-wrap gap-1.5">
            {image.colorTags.map(tag => (
              <span key={tag} className="rounded-full bg-gray-100 px-2.5 py-0.5 text-xs text-gray-600">{tag}</span>
            ))}
          </div>
        </div>
      )}
    </div>
  )
}

