import { notFound } from 'next/navigation'
import Link from 'next/link'
import { dummyImages } from '@/lib/dummy/images'
import { dummyOrders } from '@/lib/dummy/orders'
import { ProtectedImage } from '@/components/common/protected-image'
import { ImageCard } from '@/components/common/image-card'
import { MetadataSection } from '@/components/image-detail/metadata-section'
import { PurchasePanel } from '@/components/image-detail/purchase-panel'

const DEMO_USER_ID = 'user-001' // TODO: 실제 세션으로 교체
const RELATED_IMAGES_LIMIT = 8

const ASPECT_MAP = { LANDSCAPE: 'aspect-[4/3]', PORTRAIT: 'aspect-[3/4]', SQUARE: 'aspect-square' }

export async function generateMetadata({ params }) {
  const { id } = await params
  const image = dummyImages.find(img => img.id === id)
  if (!image) return { title: '이미지를 찾을 수 없습니다 | JiangsStock' }
  return { title: image.name + ' | JiangsStock' }
}

export default async function ImageDetailPage({ params }) {
  const { id } = await params
  const image = dummyImages.find(img => img.id === id)
  if (!image) notFound()

  const isPurchased = dummyOrders.some(
    o => o.userId === DEMO_USER_ID && o.status === 'COMPLETED' && o.items.some(i => i.imageId === id)
  )

  const relatedImages = dummyImages
    .filter(img => img.categoryId === image.categoryId && img.id !== id && img.isActive)
    .slice(0, RELATED_IMAGES_LIMIT)

  return (
    <div className="mx-auto max-w-screen-xl px-4 py-10 md:px-8">
      <div className="grid grid-cols-1 gap-10 lg:grid-cols-[1fr_360px]">
        <div className="space-y-8">
          <div className={ASPECT_MAP[image.orientation] + ' relative w-full overflow-hidden rounded-lg bg-gray-100'}>
            <ProtectedImage src={image.watermarkUrl} alt={image.name} fill sizes="(max-width: 1024px) 100vw, calc(100vw - 420px)" className="object-cover" />
          </div>
          <MetadataSection image={image} isPurchased={isPurchased} />
          {image.tags.length > 0 && (
            <div className="flex flex-wrap gap-2">
              {image.tags.map(tag => (
                <Link key={tag} href={'/search?q=' + encodeURIComponent(tag)} className="rounded-full bg-gray-100 px-3 py-1 text-sm text-gray-600 hover:bg-gray-200 transition-colors">{tag}</Link>
              ))}
            </div>
          )}
        </div>
        <PurchasePanel image={image} />
      </div>
      {relatedImages.length > 0 && (
        <section className="mt-16">
          <h2 className="mb-6 text-lg font-semibold text-gray-900">관련 이미지</h2>
          <div className="columns-2 gap-2 md:columns-3 lg:columns-4">
            {relatedImages.map(img => (
              <div key={img.id} className="mb-2 break-inside-avoid">
                <ImageCard image={img} showWishlist={false} />
              </div>
            ))}
          </div>
        </section>
      )}
    </div>
  )
}
